// Define WHO you are hunting for. Override per-call via the webhook body.
const body = ($json.body || {});
return [{ json: {
  person_titles: body.person_titles || [
    'Head of Partnerships','Partnerships Manager','Head of Marketing',
    'Marketing Director','Brand Manager','Sponsorship Manager','BD Manager'
  ],
  q_organization_keyword_tags: body.keywords || [
    'gaming','mobile games','esports','game publishing','gaming hardware',
    'energy drink','game studio'
  ],
  per_page: body.per_page || 10,
  page: body.page || 1
}}];

// Map enriched Apollo matches -> contactable Airtable records (real email required).
// bulk_match returns `matches[]` (entries may be null when no match was found).
// Falls back to the raw search `people[]` if enrichment is unavailable.
const src = Array.isArray($json.matches) ? $json.matches : ($json.people || []);
const records = [];
const seen = new Set();
for (const p of src) {
  if (!p) continue;
  const org = p.organization || {};
  const raw = p.email || '';
  const email = raw && !/email_not_unlocked|locked|not_unlocked/i.test(raw) && /.+@.+\..+/.test(raw) ? raw.toLowerCase() : null;
  if (!email || seen.has(email)) continue; // sender needs a real, unique address
  seen.add(email);
  records.push({ fields: {
    'Name': org.name || p.name || 'Unknown',
    'Website': org.website_url || org.primary_domain || '',
    'Industry': org.industry || '',
    'Country': p.country || org.country || '',
    'Employees': org.estimated_num_employees ? String(org.estimated_num_employees) : '',
    'Email': email,
    'Contact Name': p.name || [p.first_name, p.last_name].filter(Boolean).join(' '),
    'Title': p.title || '',
    'LinkedIn': p.linkedin_url || '',
    'Source': 'Apollo',
    'Status': 'New'
  }});
}
if (!records.length) return [];
return [{ json: { records } }];
